describe("Headers class",()=>{it("should construct a new Headers object with the provided headers",()=>{let e={"content-type":"application/json"},t=new Headers(e);expect(t.get("Content-Type")).toEqual(e["content-type"])}),it("should add headers to the Headers object",()=>{let e=new Headers;e.set("Content-Type","application/json"),expect(e.get("Content-Type")).toEqual("application/json")}),it("should overwrite headers in the Headers object",()=>{let e={"Content-Type":"application/json"},t=new Headers(e);t.set("Content-Type","text/plain"),expect(t.get("Content-Type")).toEqual("text/plain")}),it("should delete headers from the Headers object",()=>{let e={"Content-Type":"application/json"},t=new Headers(e);t.delete("Content-Type"),expect(t.get("Content-Type")).toBeNull()}),it("should return an iterator over the headers",()=>{let e={"content-type":"application/json",authorization:"Bearer 1234"},t=new Headers(e);t.append("set-cookie","AAA=123; expires=Sun, 10-Nov-2024 12:29:35 GMT"),t.append("set-cookie","BBB=456; expires=Sun, 10-Nov-2024 12:29:35 GMT");let n=t.entries(),o=n.next();expect(o.value).toStrictEqual(["authorization","Bearer 1234"]),o=n.next(),expect(o.value).toStrictEqual(["content-type","application/json"]),o=n.next(),expect(o.value).toStrictEqual(["set-cookie","AAA=123; expires=Sun, 10-Nov-2024 12:29:35 GMT"]),o=n.next(),expect(o.value).toStrictEqual(["set-cookie","BBB=456; expires=Sun, 10-Nov-2024 12:29:35 GMT"]),o=n.next(),expect(o.value).toStrictEqual(void 0)}),it("should iterate over the headers with forEach",()=>{let e={"content-type":"application/json"};new Headers(e).forEach((n,o)=>{expect(o).toStrictEqual("content-type"),expect(n).toStrictEqual("application/json")})}),it("should be returned as array type of string",()=>{let e=new Headers;e.append("set-cookie","AAA=123; expires=Sun, 10-Nov-2024 12:29:35 GMT"),e.append("set-cookie","BBB=456; expires=Sun, 10-Nov-2024 12:29:35 GMT"),expect(e.getSetCookie()).toStrictEqual(["AAA=123; expires=Sun, 10-Nov-2024 12:29:35 GMT","BBB=456; expires=Sun, 10-Nov-2024 12:29:35 GMT"])}),it("should be returned as a semicolon-delimited string",()=>{let e=new Headers;e.append("cookie","AAA=123"),e.append("cookie","BBB=456"),expect(e.get("cookie")).toStrictEqual("AAA=123; BBB=456")}),it("should be returned as a comma-delimited string",()=>{let e=new Headers;e.append("accept-encoding","zstd"),e.append("accept-encoding","br"),expect(e.get("accept-encoding")).toStrictEqual("zstd, br")})});
